#include "sound_sensor.h"
#include <Arduino.h>
#define SOUND_A 36
#define SOUND_D 35
static int _level=0;static bool _det=false;static unsigned long _l=0;
void sound_setup(){pinMode(SOUND_A,INPUT);pinMode(SOUND_D,INPUT);Serial.println("[sound] OK");}
void sound_loop(){if(millis()-_l<50)return;_l=millis();int mn=4095,mx=0;for(int i=0;i<32;i++){int s=analogRead(SOUND_A);if(s<mn)mn=s;if(s>mx)mx=s;}_level=mx-mn;_det=!digitalRead(SOUND_D);}
int sound_get_level(){return _level;}
bool sound_detected(){return _det;}
